def process_file_http(request):
    """
    HTTP-triggered variant for testing.
    In production, use the event-triggered version above.

    Deploy with --no-allow-unauthenticated to require authentication.
    """
    # Verify the request has proper authentication
    # Cloud Functions with --no-allow-unauthenticated will handle this
    # at the infrastructure level, but we add defense in depth

    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        logger.warning("Unauthenticated HTTP request rejected")
        return (json.dumps({"error": "Authentication required"}), 401,
                {"Content-Type": "application/json"})

    try:
        request_json = request.get_json(silent=True)
        if not request_json:
            return (json.dumps({"error": "JSON body required"}), 400,
                    {"Content-Type": "application/json"})

        # Validate required fields
        bucket = request_json.get("bucket")
        name = request_json.get("name")

        if not bucket or not name:
            return (json.dumps({"error": "bucket and name are required"}), 400,
                    {"Content-Type": "application/json"})

        # Create a mock context
        class MockContext:
            event_id = request_json.get("event_id", "http-trigger")
            timestamp = datetime.now(timezone.utc).isoformat()
            event_type = "HTTP"

        event = {"bucket": bucket, "name": name}
        result = process_file(event, MockContext())

        status_code = 200 if result.get("status") == "success" else 400
        return (json.dumps(result, default=str), status_code,
                {"Content-Type": "application/json"})

    except (InputValidationError, SecurityViolationError) as e:
        return (json.dumps({"error": str(e)}), 400,
                {"Content-Type": "application/json"})
    except Exception as e:
        logger.exception(f"HTTP handler error: {e}")
        return (json.dumps({"error": "Internal server error"}), 500,
                {"Content-Type": "application/json"})


